import { config } from 'frontend-config';
import { getReq, getRes } from '@meli/server-context';

import {
  CRITICAL_COOKIE_DEFAULT_VALUE,
  THIRTY_DAYS_IN_MS,
  REMOVE_LAST_SLASH_REGEX,
} from './constants';

export function getCookiePath() {
  const basePath = config.ragnar?.basePath;

  if (!basePath) {
    return undefined;
  }

  // eslint-disable-next-line security/detect-non-literal-regexp
  return new RegExp(basePath.replace(REMOVE_LAST_SLASH_REGEX, '')).exec(
    getReq().baseUrl,
  )?.[0];
}

export function setCookie({
  name,
  path,
  value = CRITICAL_COOKIE_DEFAULT_VALUE,
  ttl = THIRTY_DAYS_IN_MS,
}: {
  name: string;
  value?: string;
  path?: string;
  ttl?: number;
}) {
  const req = getReq();

  getRes().cookie(name, value, {
    httpOnly: true,
    expires: new Date(Date.now() + ttl),
    sameSite: false,
    domain: req.hostname,
    secure: req.secure,
    path,
  });
}
